import { Buffer } from "node:buffer";

const PNG_BASE64 =
  "";

export const TRAY_ICON_PNG_BASE64 = PNG_BASE64;

const pngBytes = Buffer.from(PNG_BASE64, "base64");
const icoHeader = Buffer.alloc(6);
icoHeader.writeUInt16LE(0, 0);
icoHeader.writeUInt16LE(1, 2);
icoHeader.writeUInt16LE(1, 4);
const icoDir = Buffer.alloc(16);
icoDir.writeUInt8(64, 0);
icoDir.writeUInt8(64, 1);
icoDir.writeUInt8(0, 2);
icoDir.writeUInt8(0, 3);
icoDir.writeUInt16LE(1, 4);
icoDir.writeUInt16LE(32, 6);
icoDir.writeUInt32LE(pngBytes.length, 8);
icoDir.writeUInt32LE(22, 12);

export const TRAY_ICON_ICO_BASE64 = Buffer.concat([icoHeader, icoDir, pngBytes]).toString("base64");
